package ir.tahamohamadi.publication.api.publicsite;
import ir.tahamohamadi.common.domain.LanguageCode; import ir.tahamohamadi.publication.*; import org.springframework.data.domain.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.time.LocalDate; import java.util.*;
@Service @Transactional(readOnly=true) public class PublicPublicationService {private final PublicationTranslationRepository translations;public PublicPublicationService(PublicationTranslationRepository translations){this.translations=translations;}public PublicPublicationListResponse list(LanguageCode locale,int page,int size,PublicationStage stage){Page<PublicationTranslation> values=translations.findPublishedByLanguage(locale,stage,PageRequest.of(page,size,Sort.by(Sort.Order.desc("publication.year"),Sort.Order.asc("publication.sortOrder"),Sort.Order.asc("publication.id"))));return new PublicPublicationListResponse(locale,values.map(this::dto).getContent(),page,size,values.getTotalElements(),values.getTotalPages());}public PublicPublicationResponse get(LanguageCode locale,String slug){return dto(translations.findPublishedByLanguageAndSlug(locale,slug).orElseThrow(()->new NoSuchElementException("Publication not found")));}private PublicPublicationResponse dto(PublicationTranslation t){Publication p=t.getPublication();return new PublicPublicationResponse(p.getId(),t.getSlug(),t.getTitle(),t.getAbstractText(),t.getAuthorsDisplay(),t.getVenueDisplay(),p.getPublicationStage(),p.getYear(),p.getPublishedOn(),p.getDoi(),p.getExternalUrl(),""+t.getLanguageCode(),List.of("fa","en"));}}
record PublicPublicationListResponse(LanguageCode locale,List<PublicPublicationResponse> items,int page,int size,long totalElements,int totalPages) { }
record PublicPublicationResponse(UUID id,String slug,String title,String abstractText,String authorsDisplay,String venueDisplay,PublicationStage stage,int year,LocalDate publishedOn,String doi,String externalUrl,String locale,List<String> availableLocales) { }
